      "mainEntity": [
        {
          "@type": "Question",
          "name": "How is a TPA claim disallowance accounted for in a hospital's books?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Book the approved package value as revenue and carry the balance in TPA receivables, then write the disallowed portion off to claim deductions when the TPA settles short rather than leaving it in the ledger. On a Rs 1,20,000 claim settled at Rs 1,05,000 after Rs 15,000 of non-payable consumables, Rs 15,000 goes to disallowances and the receivable closes."
          }
        },
        {
          "@type": "Question",
          "name": "What is the difference between a TPA receivable and a patient receivable?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "A TPA receivable is due from a third party administrator against a cashless claim and settles in roughly 30 to 90 days after document scrutiny, carrying a risk of partial disallowance. A patient receivable is due from the individual, is usually collected at discharge, and carries credit risk rather than documentation risk. Ageing schedules should keep the two apart."
          }
        },
        {
          "@type": "Question",
          "name": "Is TDS deducted on payments made by a TPA to a hospital?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Yes. A third party administrator deducts TDS at 10 percent under Section 194J of the Income Tax Act on payments to hospitals for cashless claims, so the hospital receives the settlement net of tax. The gross claim, not the net receipt, must be booked as revenue, and the TDS credit is matched with Form 26AS before the return is filed."
          }
        }
      ]
